// // This module implements a 16-bit down-counter with synchronous reset.
module up_counter_8bit(
    input clk,
    input reset,
    output reg [7:0] count
);

always @(posedge clk or posedge reset) begin
    if (reset)
        count <= 8'b0;
    else
        count <= count + 1;
end

endmodule
